css:
.loader {
  position: relative;
  display: inline-block;
  width: 54px;
  height: 54px;
  color: #6366f1;
  animation: spin 1.2s linear infinite;
}
.loader::before,
.loader::after {
  content: "";
  position: absolute;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: currentColor;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
}
.loader::after {
  top: auto;
  bottom: 0;
  opacity: 0.35;
}
@keyframes spin { to { transform: rotate(360deg); } }
